INSERT INTO categories (id, slug, name, description, cover_image, sort_order, created_at) VALUES (1, 'trappen', 'Trappen', 'Stalen binnen- en buitentrappen op maat — van strakke spiltrappen tot robuuste gegalvaniseerde buitentrappen.', '/images/categories/trappen.webp', 0, 1717000000);
INSERT INTO categories (id, slug, name, description, cover_image, sort_order, created_at) VALUES (2, 'leuningen', 'Leuningen', 'Leuningen en balustrades in staal, inox of glas. Veilig, strak en perfect op maat afgewerkt.', '/images/categories/leuningen.webp', 1, 1717000000);
INSERT INTO categories (id, slug, name, description, cover_image, sort_order, created_at) VALUES (3, 'poorten', 'Poorten', 'Stalen poorten en hekwerk — manueel of gemotoriseerd, sober of decoratief.', '/images/categories/poorten.webp', 2, 1717000000);
INSERT INTO categories (id, slug, name, description, cover_image, sort_order, created_at) VALUES (4, 'fietsenstallingen', 'Fietsenstallingen', 'Fietsenstallingen en overkappingen voor de publieke ruimte, bedrijven en residenties.', '/images/categories/fietsenstallingen.webp', 3, 1717000000);
INSERT INTO categories (id, slug, name, description, cover_image, sort_order, created_at) VALUES (5, 'staalconstructies', 'Staalconstructies', 'Draagstructuren, bordessen en industriële staalbouw — berekend, gelast en gemonteerd.', '/images/categories/staalconstructies.webp', 4, 1717000000);
INSERT INTO categories (id, slug, name, description, cover_image, sort_order, created_at) VALUES (6, 'gevelconstructies', 'Gevelconstructies', 'Stalen gevelconstructies en draagstructuren voor bekleding, met oog voor detail en duurzaamheid.', '/images/categories/gevelconstructies.webp', 5, 1717000000);
