INSERT INTO posts (id, slug, title, excerpt, content, cover_image, published, published_at, created_at, updated_at) VALUES (1, 'waarom-maatwerk-in-staal', 'Waarom kiezen voor maatwerk in staal?', 'Staal is sterk, duurzaam en eindeloos vormbaar. Ontdek waarom maatwerk in staal de slimme keuze is voor uw project.', '<p>Staal is een van de meest veelzijdige materialen in de bouw. Het combineert een enorme sterkte met een verrassende vormbaarheid, waardoor het zowel voor fijne details als voor zware draagstructuren ingezet kan worden.</p><p>Bij maatwerk vertrekken we altijd van uw specifieke situatie. Geen standaardmaten, maar een oplossing die exact past — esthetisch én technisch.</p><p>Bovendien is staal 100% recycleerbaar en gaat een goed afgewerkte constructie generaties lang mee.</p>', '/images/feature/atelier.webp', 1, 1717000000, 1717000000, 1717000000);
INSERT INTO posts (id, slug, title, excerpt, content, cover_image, published, published_at, created_at, updated_at) VALUES (2, 'stalen-trappen-stijl-en-duurzaamheid', 'Stalen trappen: stijl én duurzaamheid', 'Een stalen trap is meer dan een verbinding tussen twee verdiepingen. Het is een blikvanger die jaren meegaat.', '<p>Een trap is vaak het eerste wat opvalt in een ruimte. In staal krijgt u strakke lijnen, slanke profielen en een tijdloze uitstraling.</p><p>Of u nu kiest voor een zwevende binnentrap of een robuuste gegalvaniseerde buitentrap: wij tekenen, produceren en plaatsen alles in eigen beheer.</p>', '/images/categories/trappen.webp', 1, 1717086400, 1717000000, 1717000000);
INSERT INTO posts (id, slug, title, excerpt, content, cover_image, published, published_at, created_at, updated_at) VALUES (3, 'van-tekening-tot-montage', 'Van tekening tot montage: zo werkt Thimafer', 'Eén partner, van het eerste tekenwerk tot de plaatsing op de werf. Zo houden we de kwaliteit in eigen hand.', '<p>Bij Thimafer doorloopt elk project hetzelfde duidelijke traject: contact, opmeting, offerte, tekenwerk, productie, afwerking en montage.</p><p>Doordat we alles zelf doen, blijft de communicatie kort en de kwaliteit hoog.</p>', '/images/feature/werkwijze.webp', 1, 1717172800, 1717000000, 1717000000);
